import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { useWishlist } from '../context/WishlistContext';
import './Navbar.css';

const faInfoCircleRegular = {
  prefix: 'far',
  iconName: 'info-circle',
  icon: [
    16, 16,
    [],
    "",
    [
      "M8 15A7 7 0 1 1 8 1a7 7 0 0 1 0 14m0 1A8 8 0 1 0 8 0a8 8 0 0 0 0 16",
      "m8.93 6.588-2.29.287-.082.38.45.083c.294.07.352.176.288.469l-.738 3.468c-.193.897.105 1.319.808 1.319.545 0 1.178-.252 1.465-.598l.088-.416c-.2.176-.492.246-.686.246-.275 0-.375-.193-.304-.533zM9 4.5a1 1 0 1 1-2 0 1 1 0 0 1 2 0"
    ]
  ]
};

const faShoppingBagRegular = {
  prefix: 'far',
  iconName: 'shopping-bag',
  icon: [
    16, 16,
    [],
    "",
    "M8 1a2.5 2.5 0 0 1 2.5 2.5V4h-5v-.5A2.5 2.5 0 0 1 8 1m3.5 3v-.5a3.5 3.5 0 1 0-7 0V4H1v10a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V4zM2 5h12v9a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1z"
  ]
};

const LOGO = "/logo.png";

export default function Navbar() {
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);
  const { totalItems } = useWishlist();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const isActive = (path) => location.pathname === path;

  return (
    <nav className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}>
      <div className="navbar__inner container-max">
        {/* Logo - left */}
        <Link to="/" className="navbar__brand">
          <img src={LOGO} alt="SG Herbals Logo" className="navbar__logo" />
          <span className="navbar__brand-name font-headline-md">SG HERBALS</span>
        </Link>

        {/* Desktop centered nav links */}
        <div className="navbar__links">
          <Link to="/" className={`navbar__link font-label-md ${isActive('/') ? 'navbar__link--active' : ''}`}>HOME</Link>
          <Link to="/shop" className={`navbar__link font-label-md ${isActive('/shop') ? 'navbar__link--active' : ''}`}>SHOP</Link>
          <Link to="/about" className={`navbar__link font-label-md ${isActive('/about') ? 'navbar__link--active' : ''}`}>ABOUT</Link>
        </div>

        {/* Right side actions */}
        <div className="navbar__actions">
          {/* Mobile: info icon for About page */}
          <Link to="/about" className="navbar__about-mobile" title="About">
            <FontAwesomeIcon icon={faInfoCircleRegular} />
          </Link>

          {/* Desktop: bag icon linking to order list page */}
          <Link to="/wishlist" className="navbar__heart-desktop" title="Order List">
            <FontAwesomeIcon icon={faShoppingBagRegular} style={{ fontSize: '20px' }} />
            {totalItems > 0 && <span className="navbar__badge">{totalItems}</span>}
          </Link>
        </div>
      </div>
    </nav>
  );
}
